package com.Operator;
		
	
public class Arthematicop {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

			int num1 = 10;
	        int num2 = 20;

	        System.out.println("In this Arthematic operator we use: " + num1 + "and" + num2);

	        System.out.println("add" + (num1 + num2) );
	        System.out.println("Substract" + (num1 - num2) );
	        System.out.println("Multiply" + (num1 * num2) );
	        System.out.println("Divide" + (num1 / num2) );
	        System.out.println("Modulus" + (num1 % num2) );

	        //we use double for more precise division
	        double num3 = 78.96;
	        double num4 = 12.97;

	        System.out.print("precise division: " + (num3 / num4) );

	    }
	}
